import React, { useEffect, useRef } from 'react';
import { useWebRTC } from '../../hooks/useWebRTC';

interface ViewerViewProps {
  roomId: string;
  userId: string;
  onLeave: () => void;
}

export const ViewerView: React.FC<ViewerViewProps> = ({ roomId, userId, onLeave }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  const { remoteStreams, isConnected, error, joinAsViewer, leave } = useWebRTC({
    roomId,
    role: 'viewer',
    userId,
  });

  useEffect(() => {
    joinAsViewer();
  }, [joinAsViewer]);

  useEffect(() => {
    // Display the first remote stream (broadcaster's stream)
    const streams = Array.from(remoteStreams.values());
    if (streams.length > 0 && videoRef.current) {
      console.log('Setting video srcObject, stream has tracks:', streams[0].getTracks());
      videoRef.current.srcObject = streams[0];

      // Ensure video plays
      videoRef.current.play().catch(err => {
        console.error('Error playing video:', err);
      });
    }
  }, [remoteStreams]);

  const handleLeave = () => {
    leave();
    onLeave();
  };

  const hasStream = remoteStreams.size > 0;

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2>Viewing Broadcast</h2>
        <div style={styles.status}>
          {isConnected ? (
            <span style={styles.statusConnected}>● Connected</span>
          ) : (
            <span style={styles.statusDisconnected}>● Disconnected</span>
          )}
        </div>
      </div>

      <div style={styles.videoContainer}>
        <video
          ref={videoRef}
          autoPlay
          playsInline
          controls
          style={styles.video}
        />

        {!hasStream && (
          <div style={styles.overlay}>
            <p>Waiting for broadcaster to start streaming...</p>
          </div>
        )}
      </div>

      {error && <div style={styles.error}>{error}</div>}

      <div style={styles.controls}>
        <button onClick={handleLeave} style={styles.leaveButton}>
          Leave Room
        </button>
      </div>

      <div style={styles.info}>
        <p><strong>Room ID:</strong> {roomId}</p>
        <p><strong>User ID:</strong> {userId}</p>
        <p><strong>Role:</strong> Viewer</p>
        <p><strong>Streams:</strong> {remoteStreams.size}</p>
      </div>
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  container: {
    padding: '20px',
    maxWidth: '1000px',
    margin: '0 auto',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '20px',
  },
  status: {
    fontSize: '14px',
  },
  statusConnected: {
    color: 'green',
  },
  statusDisconnected: {
    color: 'red',
  },
  videoContainer: {
    position: 'relative',
    backgroundColor: '#000',
    borderRadius: '8px',
    overflow: 'hidden',
    marginBottom: '20px',
  },
  video: {
    width: '100%',
    height: 'auto',
    display: 'block',
  },
  overlay: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0, 0, 0, 0.7)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: 'white',
    fontSize: '18px',
  },
  controls: {
    display: 'flex',
    gap: '10px',
    marginBottom: '20px',
  },
  leaveButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#6c757d',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  info: {
    padding: '15px',
    backgroundColor: '#f8f9fa',
    borderRadius: '4px',
  },
  error: {
    color: 'red',
    padding: '10px',
    marginBottom: '10px',
    backgroundColor: '#fee',
    borderRadius: '4px',
  },
};
